import React from 'react'
import MainView from './components/main-view/main-view';
import './App.css';

function App() { 
	const clearLocalStorageOnStart = () => {
		// Check if the app is starting for the first time
		if (!localStorage.getItem('gameStarted')) {
		  // Clear local storage
			localStorage.clear();
			alert();

		  // Set a flag to indicate that the game has started
		  localStorage.setItem('gameStarted', true);
		}
	  };

	  // Call the function to clear local storage on app start
	  clearLocalStorageOnStart();
	return (
		<div className="App"  >


		<MainView />

		</div>

	)
}

export default App;
